define(['jquery'], function($) {
    return {
        init: function(cmid, hasTranscription, tutorUrl) {
            $(document).ready(function() {
                var container = $('.urlworkaround, .resourcecontent, .mod_url_content').first();
                if (!container.length) {
                    var iframes = $('iframe').parent();
                    if (iframes.length) { container = iframes.first(); }
                }
                
                if (container.length && !container.data('vt-injected')) {
                    container.data('vt-injected', true);
                    
                    var wrapper = $('<div style="display:flex; flex-wrap:wrap; gap:20px; align-items:stretch; margin-top:20px; justify-content:center;"></div>');
                    var videoCol = $('<div style="flex: 3; min-width: 60%;"></div>');
                    
                    // Move contents to videoCol
                    container.contents().appendTo(videoCol);
                    
                    var btnHtml = '<div style="flex: 1; min-width: 250px; padding: 20px; background:#f4f6f8; border-radius:8px; border:1px solid #ddd; display:flex; flex-direction:column; justify-content:center; text-align:center;">';
                    btnHtml += '<h3 style="margin-top:0; color:#2e7d32; font-size:20px; font-weight:bold;">🤖 Tutor IA</h3>';
                    
                    if (hasTranscription) {
                        btnHtml += '<p style="color:#2e7d32;font-weight:bold;">✔ Transcrição e Tutor disponíveis!</p>';
                        btnHtml += '<a href="' + tutorUrl + '" class="btn btn-primary" style="width:100%;font-size:16px;padding:12px; font-weight:bold;text-decoration:none;">Abrir Tutor IA</a>';
                    } else {
                        btnHtml += '<p style="color:#c62828;font-weight:bold;">⏳ Transcrição em andamento... <br>Atualize a página em breve.</p>';
                    }
                    btnHtml += '</div>';
                    
                    wrapper.append(videoCol);
                    wrapper.append($(btnHtml));
                    container.append(wrapper);
                }
            });
        }
    };
});
